import bcrypt from "bcrypt";
import userModel from "../models/user.model";
import jwt from "jsonwebtoken";
import { generateOTP, sendOTPEmail } from "./nodemailer.controller";
export const createUser = async (req, res) => {
  try {
    const { name, email, password, role } = req.body;

    const user = await userModel.findOne({ email });

    if (user) {
      return res.status(400).json({
        message: "user already exists",
        success: false,
      });
    }

    const salt = Number(process.env.SALT);

    const hashedpassword = bcrypt.hashSync(password, salt);
    const otp = generateOTP();
    const newUser = await userModel.create({
      name,
      email,
      password: hashedpassword,
      role,
      otp,
      otpExpiry: Date.now() + 5 * 60 * 1000,
    });

    await sendOTPEmail(email, otp);

    return res.status(201).json({
      data: newUser,
      message: "user created successfully",
      success: true,
    });
  } catch (error) {
    return res.status(500).json({
      message: "api error || somthing went wrong ",
      success: false,
    });
  }
};

export const verifyOTP = async (req, res) => {
  try {
    const { email, otp } = req.body;
    const user = await userModel.findOne({ email });
    if (!user || user.otp !== otp) {
      return res.status(400).json({
        message: "Invaild OTP",
      });
    }

    if (user.otpExpiry < Date.now()) {
      return res.status(400).json({
        message: "OTP expired",
      });
    }
    ((user.isVerified = true), (user.otp = null), (user.otpExpiry = null));

    await user.save();

    return res.status(200).json({
      message: "OTP verified successfully",
    });
  } catch (error) {
    console.log(error);
  }
};

export const resendOTP = async (req, res) => {
  try {
    const { email } = req.body;

    if (!email) {
      return res.status(400).json({
        message: "Email is required",
        success: false,
      });
    }

    const user = await userModel.findOne({ email });

    if (!user) {
      return res.status(400).json({
        message: "User not found",
        success: false,
      });
    }

    if (user.isVerified) {
      return res.status(400).json({
        message: "User is already verified",
        success: false,
      });
    }

    const otp = generateOTP();
    user.otp = otp;
    user.otpExpiry = Date.now() + 5 * 60 * 1000;
    await user.save();

    await sendOTPEmail(email, otp);

    return res.status(200).json({
      message: "A new OTP has been sent to your email",
      success: true,
    });
  } catch (error) {
    console.error("resendOTP error:", error);
    return res.status(500).json({
      message: "Something went wrong",
      success: false,
    });
  }
};

export const login = async (req, res) => {
  try {
    const { email, password } = req.body;

    const existingUser = await userModel.findOne({ email }).select("+password");

    if (!existingUser) {
      return res.status(400).json({
        message: "user not exists",
        success: false,
      });
    }

    const compare = bcrypt.compareSync(password, existingUser.password);
    if (!compare) {
      return res.status(400).json({
        message: "invaild password",
        success: false,
      });
    }

    if (!existingUser.isVerified) {
      return res.status(400).json({
        message: "Please verify OTP first",
      });
    }

    const token = jwt.sign(
      { id: existingUser._id, role: existingUser.role },
      process.env.TOKEN_SECRET_KEY,
      { expiresIn: "1h" },
    );

    return res.status(200).json({
      data: existingUser,
      token: token,
      message: "login suucessful",
      success: true,
    });
  } catch (error) {
    return res.status(500).json({
      message: "api error || somthing went wrong ",
      success: false,
    });
  }
};

