sourcesContent:
import { v2 as cloudinary } from "cloudinary";
import fs from "fs";

cloudinary.config({
  cloud_name: process.env.CLOUDINARY_CLOUD_NAME,
  api_key: process.env.CLOUDINARY_API_KEY,
  api_secret: process.env.CLOUDINARY_API_SECRET,
});

const uploadOnCloudinary = async (localFilePath) => {
  try {
    if (!localFilePath) {
      return null;
    }
    // upload the file on cloudinary
    const response = await cloudinary.uploader.upload(localFilePath, {
      folder: localFilePath.includes("avatars")
        ? "library/users/avatars"
        : "library/books/covers",
      resource_type: "auto",
      quality: "auto",
    });
    // file has been uplaoded successfully
    console.log("file is  uploaded on cloudinary", response.url);

    return response;
  } catch (error) {
    fs.unlinkSync(localFilePath); // remove the loacally saved file as the uplaod operation got faild
    return null;
  }
};

export const deleteCloudinaryImage = async (public_id) => {
  await cloudinary.uploader.destroy(public_id, {
    resource_type: "image",
    invalidate: true,
  });
};

